PY3 = PY_MAJOR_VERSION >= 3

cdef bytes str_to_bytes(object s):
	if PY3:
		return s.encode('ascii')
	else:
		return s

cdef str bytes_to_str(object s):
	if PY3:
		return s.decode('ascii')
	else:
		return s

